MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(asset:Asset)
WHERE (aas.idShort CONTAINS 'UR3e' OR aas.idShort CONTAINS 'UR-3e' OR aas.idShort CONTAINS 'ur3e')
   OR (asset.globalAssetId CONTAINS 'UR3e' OR asset.globalAssetId CONTAINS 'ur3e')
   OR EXISTS {
     MATCH (aas)-[:HAS_SUBMODEL]->(sm:Submodel)-[:HAS_ELEMENT*]->(prop:Property)
     WHERE prop.idShort = 'location' AND prop.value = 'Hall 4'
   }
   OR EXISTS {
     MATCH (aas)-[:HAS_SUBMODEL]->(sm:Submodel)-[:HAS_ELEMENT*]->(prop:Property)
     WHERE prop.idShort = 'hall' AND prop.value = '4'
   }
RETURN aas.id AS aas_id, aas.idShort AS id_short, asset.globalAssetId AS global_asset_id, asset.assetKind
